        document.getElementById('temp_f').textContent = data.temperature_f;
    } catch (error) {
        console.error('Error fetching temperature:', error);
        alert('Failed to get new reading');
    }
} View raw code How Does it Work? We’ll briefly explain this JavaScript code. Alternatively, you can skip to the next section . Turn LED ON / OFF The turnOn() function makes a request on the /lighton path. The response will be a JSON in the following format (this is handled in the MicroPython file). {
